11→const val SELECTED_TRAFFIC_GRANULARITY_KEY = "SELECTED_TRAFFIC_GRANULARITY_KEY"
12→
13→@Singleton
14→class SelectedTrafficGranularityManager @Inject constructor(private val sharedPrefs: SharedPreferences) {
15→    private val _liveSelectedGranularity = MutableLiveData<StatsGranularity>()
16→    val liveSelectedGranularity: LiveData<StatsGranularity>
17→        get() {
18→            if (_liveSelectedGranularity.value == null) {
19→                val selectedSection = getSelectedTrafficGranularity()
20→                _liveSelectedGranularity.value = selectedSection
21→            }
22→            return _liveSelectedGranularity
23→        }
24→
25→    fun getSelectedTrafficGranularity(): StatsGranularity {
26→        val value = sharedPrefs.getString(SELECTED_TRAFFIC_GRANULARITY_KEY, DAYS.name)
27→        return value?.let { StatsGranularity.valueOf(value) } ?: DAYS
28→    }
29→
30→    fun setSelectedTrafficGranularity(selectedTrafficGranularity: StatsGranularity) {
