    override fun buildNavigateAction(uri: UriWrapper): NavigateAction {
        val pathSegments = uri.pathSegments
        val length = pathSegments.size

        return when {
            jetpackFeatureRemovalPhaseHelper.shouldShowStaticPage() -> OpenJetpackStaticPosterView
            else -> parseStatsDeepLink(pathSegments)
        }
    }

    private fun parseStatsDeepLink(pathSegments: List<String>): NavigateAction {
        val length = pathSegments.size

        // Handle traditional timeframe URLs: /stats/day/$site or /stats/day
        val site = pathSegments.getOrNull(length - 1)?.toSite()
        val statsTimeframe = pathSegments.getOrNull(length - 2)?.toStatsTimeframe()

        // Handle new format URLs
        when {
            length >= 2 && pathSegments[0] == "stats" -> {
                val firstParam = pathSegments[1]

                when (firstParam) {
                    "traffic" -> {
                        return handleTrafficDeepLink(pathSegments, length)
                    }
                    "subscribers" -> {
                        return handleSubscribersDeepLink(pathSegments, length)
                    }
                    else -> {
                        // Traditional format: /stats/$timeframe or /stats/$timeframe/$site
                        val timeframe = firstParam.toStatsTimeframe()
                        return when {
                            timeframe != null && site != null -> OpenStatsForSiteAndTimeframe(site, timeframe)
