                return OpenStatsForSiteAndTimeframe(site, statsTimeframe)
            }
            site != null -> {
                return OpenStatsForSite(site)
            }
            statsTimeframe != null -> {
                return OpenStatsForTimeframe(statsTimeframe)
            }
            else -> {
                return OpenStats
            }
        }
    }

    private fun handleTrafficDeepLink(pathSegments: List<String>, length: Int): NavigateAction {
